#include <stdio.h>
int main() {
    int T, N, M, pos, i, j;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        int arr[N];
        for (i = 0; i < N; i++) arr[i] = 0;
        for (i = 0; i < M; i++) {
            scanf("%d", &pos);
            for (j = 0; j < N; j++) {
                if (j <= pos) arr[j] = pos - j;
                else arr[j] = j - pos;
            }
        }
        for (i = 0; i < N; i++) {
            int max = 0;
            for (j = 0; j < M; j++) {
                int temp;
                scanf("%d", &pos);
                if (i <= pos) temp = pos - i;
                else temp = i - pos;
                if (temp > max) max = temp;
            }
            printf("%d ", max);
        }
        printf("\n");
    }
    return 0;
}

