import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[] arr = new int[N];
            int[] positions = new int[M];
            for (int i = 0; i < M; i++) positions[i] = sc.nextInt();
            for (int i = 0; i < N; i++) {
                int max = 0;
                for (int j = 0; j < M; j++) {
                    int temp;
                    int pos = positions[j];
                    if (i <= pos) temp = pos - i;
                    else temp = i - pos;
                    if (temp > max) max = temp;
                }
                System.out.print(max + " ");
            }
            System.out.println();
        }
    }
}

